selector_to_html = {"a[href=\"https://en.wikipedia.org/wiki/Log-normal_distribution\"]": "<img src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/8/89/Log-normal-pdfs.png/330px-Log-normal-pdfs.png\" alt=\"Wikipedia thumbnail\" style=\"float:left; margin-right:10px;\"><p>In probability theory, a <b>log-normal</b> (or <b>lognormal</b>) <b>distribution</b> is a continuous probability distribution of a random variable whose logarithm is normally distributed. Thus, if the random variable <span class=\"texhtml mvar\" style=\"font-style:italic\">X</span> is log-normally distributed, then <span class=\"texhtml \"><i>Y</i> = ln <i>X</i></span> has a normal distribution. Equivalently, if <span class=\"texhtml mvar\" style=\"font-style:italic\">Y</span> has a normal distribution, then the exponential function of <span class=\"texhtml mvar\" style=\"font-style:italic\">Y</span>, <span class=\"texhtml \"><i>X</i> = exp(<i>Y</i>)</span>, has a log-normal distribution. A random variable which is log-normally distributed takes only positive real values. It is a convenient and useful model for measurements in exact and engineering sciences, as well as medicine, economics and other topics (e.g., energies, concentrations, lengths, prices of financial instruments, and other metrics).</p>", "a[href^=\"https://en.wikipedia.org/wiki/Log-normal_distribution#\"]": "<img src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/8/89/Log-normal-pdfs.png/330px-Log-normal-pdfs.png\" alt=\"Wikipedia thumbnail\" style=\"float:left; margin-right:10px;\"><p>In probability theory, a <b>log-normal</b> (or <b>lognormal</b>) <b>distribution</b> is a continuous probability distribution of a random variable whose logarithm is normally distributed. Thus, if the random variable <span class=\"texhtml mvar\" style=\"font-style:italic\">X</span> is log-normally distributed, then <span class=\"texhtml \"><i>Y</i> = ln <i>X</i></span> has a normal distribution. Equivalently, if <span class=\"texhtml mvar\" style=\"font-style:italic\">Y</span> has a normal distribution, then the exponential function of <span class=\"texhtml mvar\" style=\"font-style:italic\">Y</span>, <span class=\"texhtml \"><i>X</i> = exp(<i>Y</i>)</span>, has a log-normal distribution. A random variable which is log-normally distributed takes only positive real values. It is a convenient and useful model for measurements in exact and engineering sciences, as well as medicine, economics and other topics (e.g., energies, concentrations, lengths, prices of financial instruments, and other metrics).</p>", "a[href=\"#exppoly-model\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">1. ExpPoly Model<a class=\"headerlink\" href=\"#exppoly-model\" title=\"Link to this heading\">\u00b6</a></h2><p>The <a class=\"reference internal\" href=\"../apidocs/stacie.model.html#stacie.model.ExpPolyModel\" title=\"stacie.model.ExpPolyModel\"><span class=\"xref myst py py-class\">ExpPolyModel</span></a> is defined as:</p>", "a[href=\"#pade-model\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">2. Pade Model<a class=\"headerlink\" href=\"#pade-model\" title=\"Link to this heading\">\u00b6</a></h2><p>The <a class=\"reference internal\" href=\"../apidocs/stacie.model.html#stacie.model.PadeModel\" title=\"stacie.model.PadeModel\"><span class=\"xref myst py py-class\">PadeModel</span></a> is defined as:</p>", "a[href=\"#model-spectrum\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Model Spectrum<a class=\"headerlink\" href=\"#model-spectrum\" title=\"Link to this heading\">\u00b6</a></h1><p>STACIE supports three models for fitting the low-frequency part of the power spectrum.\nIn all models, the value at zero frequency corresponds to the autocorrelation integral.</p>", "a[href=\"#lorentz-model\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">3. Lorentz Model<a class=\"headerlink\" href=\"#lorentz-model\" title=\"Link to this heading\">\u00b6</a></h2><p>The <a class=\"reference internal\" href=\"../apidocs/stacie.model.html#stacie.model.LorentzModel\" title=\"stacie.model.LorentzModel\"><span class=\"xref myst py py-class\">LorentzModel</span></a> assumes that for large time lags,\n<span class=\"math notranslate nohighlight\">\\(\\Delta_t\\)</span>, the autocorrelation function (ACF) exhibits an exponential decay\nsuperimposed with a white noise background:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
